#!/usr/bin/env python3
"""
Find all concrete struct types implementing runtime.Object across
kubernetes/api and kubernetes/apimachinery repositories.

Criteria for inclusion:
  - Has DeepCopyObject() runtime.Object method (generated or hand-written)
  - Is a concrete struct type (not an interface, not a function type)
  - Has GetObjectKind() (via TypeMeta embedding or explicit method)
  - Is NOT a List type (name ends with "List" or is exactly "List")
  - Is NOT in a test/testing/testapigroup package
  - Is NOT a generated file itself

Output: /workspace/implementors.json
"""

import json
import os
import re
import sys
from pathlib import Path

REPOS = {
    "/workspace/api": "kubernetes/api",
    "/workspace/apimachinery": "kubernetes/apimachinery",
}

# Path segments that mark test/internal-only packages to exclude entirely
EXCLUDED_PATH_SEGMENTS = {
    "/testing/",
    "/testapigroup/",
    "/pkg/test/",
    "/pkg/watch/",   # functionFakeRuntimeObject is a func type, not a struct
}

# Regex: match generated DeepCopyObject receiver declarations
# e.g.  func (in *Foo) DeepCopyObject() runtime.Object {
#        func (in *Unknown) DeepCopyObject() Object {   (runtime pkg uses unqualified Object)
RE_DEEPCOPY_OBJECT = re.compile(
    r"^func\s+\(in\s+\*(\w+)\)\s+DeepCopyObject\(\)\s+(?:runtime\.)?Object\s*\{"
)

# Regex: match hand-written DeepCopyObject (same signature, any file)
RE_DEEPCOPY_OBJECT_HANDWRITTEN = re.compile(
    r"^func\s+\(\w+\s+\*(\w+)\)\s+DeepCopyObject\(\)\s+(?:runtime\.)?Object\s*\{"
)

# Regex: struct definition
RE_STRUCT_DEF = re.compile(r"^type\s+(\w+)\s+struct\b")

# Regex: type definition that resolves to a struct (e.g. type InternalEvent watch.Event)
RE_TYPE_DEF = re.compile(r"^type\s+(\w+)\s+\w[\w.]*\s*$")

# Regex: GetObjectKind method on a type
RE_GET_OBJECT_KIND = re.compile(
    r"^func\s+\(\w+\s+\*?(\w+)\)\s+GetObjectKind\(\)"
)

# Regex: TypeMeta embedding inside a struct body
RE_TYPEMETA_EMBED = re.compile(
    r"^\s+(?:\w+\.)?TypeMeta\b"
)


def is_excluded_path(path: str) -> bool:
    """Return True if the file path belongs to an excluded package."""
    for seg in EXCLUDED_PATH_SEGMENTS:
        if seg in path:
            return True
    if "_test.go" in path:
        return True
    return False


def is_list_type(name: str) -> bool:
    """Return True if the type name indicates a List type."""
    return name == "List" or name.endswith("List")


def get_repo_and_relpath(abs_path: str) -> tuple[str, str]:
    """Return (repo_name, relative_file_path) for an absolute path."""
    for root, repo in REPOS.items():
        if abs_path.startswith(root + "/"):
            rel = abs_path[len(root) + 1:]
            return repo, rel
    raise ValueError(f"Path not under any known repo: {abs_path}")


def find_source_files(directory: str) -> list[str]:
    """Return non-generated, non-test Go source files in a directory."""
    result = []
    try:
        for entry in os.scandir(directory):
            if not entry.is_file():
                continue
            name = entry.name
            if not name.endswith(".go"):
                continue
            if name.startswith("zz_generated") or name.endswith("_test.go"):
                continue
            if "generated" in name and name.endswith(".go"):
                # skip generated.pb.go, generated.proto.go, etc.
                if "generated" in name:
                    continue
            result.append(entry.path)
    except PermissionError:
        pass
    return result


def parse_directory(directory: str) -> dict:
    """
    Parse all non-generated Go files in a directory.
    Returns:
      {
        'structs': set of struct type names,
        'type_defs': set of named type definitions (may be struct-backed),
        'get_object_kind': set of type names with GetObjectKind(),
        'typemeta_structs': set of struct names that embed TypeMeta,
        'file_map': {type_name: source_file_path},
      }
    """
    structs = set()
    type_defs = set()
    get_object_kind_types = set()
    typemeta_structs = set()
    file_map = {}

    for src_file in find_source_files(directory):
        try:
            lines = Path(src_file).read_text(encoding="utf-8", errors="replace").splitlines()
        except OSError:
            continue

        in_struct = None
        brace_depth = 0

        for line in lines:
            stripped = line.strip()

            # Detect struct definitions
            m = RE_STRUCT_DEF.match(stripped)
            if m:
                type_name = m.group(1)
                structs.add(type_name)
                file_map[type_name] = src_file
                in_struct = type_name
                brace_depth = 1
                continue

            # Detect plain type definitions (non-struct)
            m = RE_TYPE_DEF.match(stripped)
            if m:
                type_name = m.group(1)
                type_defs.add(type_name)
                if type_name not in file_map:
                    file_map[type_name] = src_file
                continue

            # Track brace depth inside struct
            if in_struct:
                brace_depth += stripped.count("{") - stripped.count("}")
                if brace_depth <= 0:
                    in_struct = None
                    brace_depth = 0
                    continue
                # Check for TypeMeta embedding
                if RE_TYPEMETA_EMBED.match(line):
                    typemeta_structs.add(in_struct)

            # Detect GetObjectKind methods
            m = RE_GET_OBJECT_KIND.match(stripped)
            if m:
                get_object_kind_types.add(m.group(1))

    return {
        "structs": structs,
        "type_defs": type_defs,
        "get_object_kind": get_object_kind_types,
        "typemeta_structs": typemeta_structs,
        "file_map": file_map,
    }


def extract_deepcopy_object_types(deepcopy_file: str) -> list[str]:
    """Extract type names with DeepCopyObject() from a generated deepcopy file."""
    types = []
    try:
        lines = Path(deepcopy_file).read_text(encoding="utf-8", errors="replace").splitlines()
    except OSError:
        return types
    for line in lines:
        m = RE_DEEPCOPY_OBJECT.match(line.strip())
        if m:
            types.append(m.group(1))
    return types


def extract_handwritten_deepcopy_types(src_file: str) -> list[str]:
    """Extract type names with hand-written DeepCopyObject() from a source file."""
    types = []
    try:
        lines = Path(src_file).read_text(encoding="utf-8", errors="replace").splitlines()
    except OSError:
        return types
    for line in lines:
        m = RE_DEEPCOPY_OBJECT_HANDWRITTEN.match(line.strip())
        if m:
            types.append(m.group(1))
    return types


def is_concrete_struct(type_name: str, dir_info: dict) -> bool:
    """
    Return True if type_name is a concrete struct (or struct-backed type)
    that implements runtime.Object (has GetObjectKind + TypeMeta or explicit method).
    """
    structs = dir_info["structs"]
    type_defs = dir_info["type_defs"]
    get_object_kind = dir_info["get_object_kind"]
    typemeta_structs = dir_info["typemeta_structs"]

    # Must be a struct or a named type (which may be struct-backed)
    is_struct = type_name in structs
    is_type_def = type_name in type_defs

    if not is_struct and not is_type_def:
        return False

    # Must have GetObjectKind (via TypeMeta embedding or explicit method)
    has_get_object_kind = (
        type_name in typemeta_structs or
        type_name in get_object_kind
    )

    return has_get_object_kind


def main():
    results = []
    seen = set()  # (repo, rel_file, struct_name)

    for repo_root, repo_name in REPOS.items():
        # --- Pass 1: Process zz_generated.deepcopy.go files ---
        for deepcopy_file in sorted(Path(repo_root).rglob("zz_generated.deepcopy.go")):
            deepcopy_path = str(deepcopy_file)

            if is_excluded_path(deepcopy_path):
                continue

            directory = str(deepcopy_file.parent)
            dir_info = parse_directory(directory)

            for type_name in extract_deepcopy_object_types(deepcopy_path):
                if is_list_type(type_name):
                    continue

                if not is_concrete_struct(type_name, dir_info):
                    continue

                src_file = dir_info["file_map"].get(type_name)
                if not src_file:
                    continue

                _, rel_file = get_repo_and_relpath(src_file)
                key = (repo_name, rel_file, type_name)
                if key in seen:
                    continue
                seen.add(key)

                results.append({
                    "repo": repo_name,
                    "file": rel_file,
                    "struct_name": type_name,
                })

        # --- Pass 2: Hand-written DeepCopyObject() implementations ---
        for src_file in sorted(Path(repo_root).rglob("*.go")):
            src_path = str(src_file)

            if is_excluded_path(src_path):
                continue
            if "zz_generated" in src_file.name:
                continue
            if "generated" in src_file.name:
                continue

            hand_types = extract_handwritten_deepcopy_types(src_path)
            if not hand_types:
                continue

            directory = str(src_file.parent)
            dir_info = parse_directory(directory)

            for type_name in hand_types:
                if is_list_type(type_name):
                    continue

                if not is_concrete_struct(type_name, dir_info):
                    continue

                # Find the actual source file for this type
                actual_src = dir_info["file_map"].get(type_name, src_path)
                _, rel_file = get_repo_and_relpath(actual_src)

                key = (repo_name, rel_file, type_name)
                if key in seen:
                    continue
                seen.add(key)

                results.append({
                    "repo": repo_name,
                    "file": rel_file,
                    "struct_name": type_name,
                })

    # Sort: repo → file → struct_name
    results.sort(key=lambda r: (r["repo"], r["file"], r["struct_name"]))

    output_path = "/workspace/implementors.json"
    with open(output_path, "w", encoding="utf-8") as f:
        json.dump(results, f, indent=2)

    print(f"Written {len(results)} entries to {output_path}")

    # Summary by repo
    by_repo = {}
    for r in results:
        by_repo.setdefault(r["repo"], 0)
        by_repo[r["repo"]] += 1
    for repo, count in sorted(by_repo.items()):
        print(f"  {repo}: {count} types")


if __name__ == "__main__":
    main()

